arguments.command:
python3 << 'EOF'
import pandas as pd, glob, numpy as np
def load(prefix):
    return pd.concat([pd.read_csv(f) for f in sorted(glob.glob(f"{prefix}_*.csv"))], ignore_index=True)
users = load("user")
vc = users.city.value_counts()
print("Full distribution of users per city (sorted desc):")
for c,n in vc.items():
    print(f"{n:5d}  {c}")
EOF

